sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?county ?sviRecord ?socioeconomicScore ?windEventCount
WHERE {
  ?county a goo:County ;
          goo:locatedInState gokg:TexasState .
  ?sviRecord a goo:SVIRecord ;
             goo:representsCounty ?county ;
             goo:sviYear 2020 ;
             goo:sviSocioeconomicTheme ?socioeconomicScore .
  FILTER (?socioeconomicScore >= 0.8)
  {
    SELECT ?county (COUNT(DISTINCT ?event) AS ?windEventCount)
    WHERE {
      ?event a goo:StormEventRecord ;
             goo:occurredInState gokg:TexasState ;
             goo:occurredInCounty ?county ;
             goo:stormEventType ?eventType ;
             goo:eventStartTime ?eventStart .
      FILTER (YEAR(?eventStart) = 2020)
      FILTER (REGEX(STR(?eventType), "Wind", "i"))
    }
    GROUP BY ?county
  }
  FILTER (?windEventCount >= 12)
}
ORDER BY DESC(?socioeconomicScore) DESC(?windEventCount) ?county
LIMIT 10
